class BfsBureau:
    weight: list[int]
    dist_bridge: list[int]
    passable_int: int
    bridge_passable_int: int
    STRIDE: int
    BRIDGE_STRIDE: int

    @classmethod
    def init(cls):
        W, H = Map.W, Map.H

        dist = [1000001] * 3136
        weight = [1000000] * 3136

        row_inf = [1000000] * H
        row_1 = [1] * H
        for x in range(W):
            base = (x + 3) * 56 + 3
            dist[base:base + H] = row_inf
            weight[base:base + H] = row_1

        cls.dist_bridge = dist
        cls.weight = weight

        S = H + 1
        cls.STRIDE = S
        col_mask = (1 << H) - 1
        p = 0
        for x in range(W):
            p |= col_mask << (x * S)
        cls.passable_int = p

        BS = H + 3
        cls.BRIDGE_STRIDE = BS
        bp = 0
        for x in range(W):
            bp |= col_mask << (x * BS)
        cls.bridge_passable_int = bp



    @classmethod
    def update(cls):
        tile_info = Map.tile_info
        _w = cls.weight
        _S = cls.STRIDE
        _BS = cls.BRIDGE_STRIDE

        for pos in chain(Map.nearby_tiles, Map.new_syms):
            x, y = pos.x, pos.y
            ti = tile_info[x][y]

            idx = ((pos.x + 3) * 56 + (pos.y + 3))
            _bit_mask = 1 << (x * _S + y)
            _bridge_bit = 1 << (x * _BS + y)

            if ti.env != Environment.WALL:
                if ti.easily_passable:
                    _w[idx] = 1
                    cls.passable_int |= _bit_mask
                elif ti.has_building:
                    _w[idx] = 1000000
                    cls.passable_int &= ~_bit_mask
                else:
                    _w[idx] = 2
                    cls.passable_int |= _bit_mask
            else:
                _w[idx] = 1000000
                cls.passable_int &= ~_bit_mask

            if (
                ti.env == Environment.EMPTY and
                (
                    (not ti.has_building) or
                    ((etype := ti.entity_type) == EntityType.MARKER) or
                    (ti.is_building_ally and (
                        etype == EntityType.ROAD or etype == EntityType.CORE))
                )
            ):
                cls.dist_bridge[idx] = 1000000
                cls.bridge_passable_int |= _bridge_bit
            else:
                cls.dist_bridge[idx] = 1000001
                cls.bridge_passable_int &= ~_bridge_bit



    @classmethod
    def dists_from_pos(cls, pos: Position):
        dist = cls.dist_global[:]

        si = (pos.x + 3) * 56 + (pos.y + 3)
        dist[si] = 0

        frontier = [si]
        d = 1
        while frontier:
            nxt = []
            _a = nxt.append
            for idx in frontier:
                ni = idx + -1
                if dist[ni] == 1000000:
                    dist[ni] = d
                    _a(ni)
                ni = idx + 55
                if dist[ni] == 1000000:
                    dist[ni] = d
                    _a(ni)
                ni = idx + 56
                if dist[ni] == 1000000:
                    dist[ni] = d
                    _a(ni)
                ni = idx + 57
                if dist[ni] == 1000000:
                    dist[ni] = d
                    _a(ni)
                ni = idx + 1
                if dist[ni] == 1000000:
                    dist[ni] = d
                    _a(ni)
                ni = idx + -55
                if dist[ni] == 1000000:
                    dist[ni] = d
                    _a(ni)
                ni = idx + -56
                if dist[ni] == 1000000:
                    dist[ni] = d
                    _a(ni)
                ni = idx + -57
                if dist[ni] == 1000000:
                    dist[ni] = d
                    _a(ni)
            frontier = nxt
            d += 1

        result = [[0] * (Map.H + 1) for _ in range(Map.W + 1)]
        for x in range(Map.W + 1):
            row = result[x]
            base = (x + 3) * 56 + 3
            for y in range(Map.H + 1):
                v = dist[base + y]
                row[y] = 1000000 if v >= 1000000 else v
        return result


