# ============================================================

class BuilderState(Enum):
    UNKNOWN = 0
    EXPLORE = 1
    ROUTE = 2
    BUILD_HARVESTER = 3


# ============================================================
# Color
# ============================================================

class Color:
    WHITE = (255, 255, 255)
    RED = (255, 0, 0)
    GREEN = (0, 255, 0)
    BLUE = (0, 0, 255)
    BLACK = (0, 0, 0)
