# ============================================================
# DarkForest
# ============================================================

class DarkForest:
    nodes: list[TreeNode | None] = [None] * 3136  # should be 56x56 = 3136
    flow: list[int]        # pressure in subtree
    pressure: list[int]    # pressure in tree
    ally_core_connected: list[bool]
    sink_set: set[int]


    @classmethod
    def init(cls):
        cls.nodes[0] = TreeNode()  # virtual super-root
        cls.nodes[0].up = None


    @classmethod
    def add_edge(cls, u: int, v: int):
        # register (u,v) edge: u.up = v
        ns = cls.nodes
        if ns[u] is None:
            ns[u] = TreeNode()

        if v in Unit.core_pos_set:
            ns[u].up = 0  # 0 is special for ally core
        else:
            ns[u].up = v


    @classmethod
    def remove_node(cls, u: int):
        # Destroy node u. Any node with up=u will be severed automagically in compute func.
        cls.nodes[u] = None


    @classmethod
    def compute(cls):

        core_pos_set = Unit.core_pos_set
        harvesters = Map.harvester_set
        ns = DarkForest.nodes

        harvest = [0] * 3136
        for h in harvesters:
            accepting = []
            if ns[(h -1)] is not None:
                accepting.append((h -1))
            if ns[(h +1)] is not None:
                accepting.append((h +1))
            if ns[(h -56)] is not None:
                accepting.append((h -56))
            if ns[(h +56)] is not None:
                accepting.append((h +56))

            if accepting:
                share = 360 // len(accepting)
                for neighbor in accepting:
                    harvest[neighbor] += share

        # indegree thingy
        cls.flow = [0] * 3136
        cls.pressure = [0] * 3136
        flow = cls.flow
        pressure = cls.pressure
        cc = [0] * 3136

        if ns[171] is not None:
            if (par := ns[171].up) is not None:  # if we have a .up

                # check if the parent is alive
                if ns[par] is not None:
                    cc[par] += 1
                else:
                    ns[171].up = None  # parent is an empty cell, set this to root
