        # lookup table kills the per-harvester integer division
        _sh = (0, 360, 180,
               120, 90)
        for h in harvesters:
            _n0 = h -1
            _e0 = ns[_n0] is not None
            _n1 = h +1
            _e1 = ns[_n1] is not None
            _n2 = h -56
            _e2 = ns[_n2] is not None
            _n3 = h +56
