# ============================================================
# TileInfo
# ============================================================

class TileInfo:
    __slots__ = (
        'env', 'round', 'easily_passable', 
        'has_building', 'building_hp', 'is_building_ally', 'entity_type',
        'has_bot', 'bot_hp', 'is_bot_ally',
    )

    env: Environment
    round: int

    easily_passable: bool  # (allied core)/road/conveyor/bridge/splitter, maybe deprecated?

    has_building: bool  # non-marker building
    building_hp: int
    is_building_ally: bool
    entity_type: EntityType | None

    has_bot: bool  # non-self builder bot
    bot_hp: int
    is_bot_ally: bool


# ============================================================
# TreeNode
# ============================================================

class TreeNode:
    __slots__ = ('up',)
    up: int | None  # can be detached. if None then is root


# total flow/harvester is set to 360 (highly divisible number)
# bottleneck of a route is 4 harvesters = 4 * 360 = 1440 pressure
# probably stop early


# ============================================================
# Unit
# ============================================================

class Unit:
    core_pos: Position
    core_pos_list: list[tuple[int, int]]
    core_pos_set: set[int]

    @staticmethod
    def init():
        BfsBureau.init()

        core_id = Globals.ct.get_tile_building_id(Globals.ct.get_position())
        Unit.core_pos = Globals.ct.get_position(core_id)
        x = Unit.core_pos.x
        y = Unit.core_pos.y
        Unit.core_pos_list = [
            (x , y -1),
            (x +1, y -1),
            (x +1, y ),
            (x +1, y +1),
            (x , y +1),
            (x -1, y +1),
            (x -1, y ),
            (x -1, y -1),
            (x , y ),
        ]
        idx = ((x + 3) * 56 + (y + 3))
        Unit.core_pos_set = {
            idx -1,
            idx +55,
            idx +56,
            idx +57,
            idx +1,
            idx -55,
            idx -56,
            idx -57,
            idx ,
        }


    @classmethod
    def start_turn(cls):
        Globals.start_tick()
        MarketMaker.refresh()

        Profiler.start()
        Map.fill_tile_info()
        Profiler.end("""fill_tile_info""")

        Profiler.start()
        BfsBureau.update()
        Profiler.end("""BfsBureau.update""")


    @classmethod
    def run_turn(cls):
        pass

    @classmethod
    def end_turn(cls):

        if Globals.round == 667:
            Profiler.report()
        print(f'scale ratio {MarketMaker.scale_ratio:.2f}')


# ============================================================
# Util
# ============================================================

class Util:
    @staticmethod
    def on_the_map(pos: Position) -> bool:
        return 0 <= pos.x < Map.W and 0 <= pos.y < Map.H

    @staticmethod
    def rand_pos() -> Position:
        return Position(random.randrange(Map.W), random.randrange(Map.H))


    @staticmethod
    def is_cardinal(dir: Direction) -> bool:
        # not great, to optimise, create polyfill for Direction
        dx, dy = dir.delta()
        return (dx == 0) ^ (dy == 0)

    @staticmethod
    def is_diagonal(dir: Direction) -> bool:
        dx, dy = dir.delta()
        return dx != 0 and dy != 0

    @staticmethod
    def get_rounds_left() -> int:
        return 2000 - Globals.round


# ============================================================
# Builder
# ============================================================

class Builder(Unit):
    state: BuilderState | int
    state_map: dict

    @classmethod
    def init(cls):
        super().init()
        Explore.init()
        DarkForest.init()

        cls.state_map = {
            BuilderState.EXPLORE: cls.state_explore,
            BuilderState.BUILD_HARVESTER: cls.state_build_harvester,
            BuilderState.ROUTE: cls.state_route,
        }
        cls.state = BuilderState.EXPLORE


    @classmethod
    def start_turn(cls):
        super().start_turn()

        Symmetry.run_sym_check()
        DarkForest.fcompute()
        OreExecutive.fill()

        Symmetry.debug()
                



    @classmethod
    def run_turn(cls):
        cls.state, pos = cls.determine_state()
        cls.state_map[cls.state](pos)


    @classmethod
    def end_turn(cls):
        super().end_turn()

        Profiler.start()
        HealExecutor.execute_heal_attempt()
        Profiler.end("""HealExecutor.execute_heal_attempt""")

    @classmethod
    def state_explore(cls, pos):
        Pathfinder.move_to(pos, ban_target_pos=False)

    @classmethod
    def state_route(cls, _):
        RouteToCore.do_routing()

    @classmethod
    def state_build_harvester(cls, pos):
        OreExecutive.go_build_harvester(pos)

    @classmethod
    def determine_state(cls):
        if RouteToCore.is_active:
            return BuilderState.ROUTE, None

        hpos = OreExecutive.get_target()
        if hpos is not None:
            return BuilderState.BUILD_HARVESTER, hpos

        return BuilderState.EXPLORE, Explore.get_target()


# ============================================================
# Core
# ============================================================

class Core(Unit):
    num_spawned: int = 0

    @classmethod
    def init(cls):
        super().init()

    @classmethod
    def start_turn(cls):
        super().start_turn()
        print(f'est income: {MarketMaker.est_income}')


    @classmethod
    def spawn(cls):
        # rework this
        pos = Globals.ct.get_position().add(random.choice(Constants.DIRECTIONS))
        if Globals.ct.can_spawn(pos):
            Globals.ct.spawn_builder(pos)
            cls.num_spawned += 1

    @classmethod
    def run_turn(cls):
        if cls.num_spawned < 3 or MarketMaker.ti > 1000:
            if cls.num_spawned < 5:
                cls.spawn()

    @classmethod
    def end_turn(cls):
        super().end_turn()

        if Globals.round > 666:
            Globals.ct.resign()


